import { useEffect, useRef } from 'react';
import { trapFocus } from '../a11y/trap-focus';
import './whatsnew.css';

interface Props { onClose: () => void; }

const ITEMS: ReadonlyArray<{ tag: string; body: string }> = [
  { tag: 'Achievements', body: '12 medals — earn them by speed-solving, going flawless, and stacking daily streaks.' },
  { tag: 'Replay viewer', body: 'After a win, scrub through every move you made — or hit Play for a 10-second time-lapse.' },
  { tag: 'Custom builder', body: 'Design your own 10×10 puzzle; we validate it has a unique solution and hand you a share link.' },
  { tag: 'Help center', body: 'Press ? any time for the keyboard cheatsheet and nonogram technique guide.' },
  { tag: 'Customization', body: 'Pick an accent color, cell border style, and clue typography.' },
  { tag: 'Welcome back', body: 'Coming back after a few days off? You get a small heads-up with the daily.' },
  { tag: 'Install', body: 'Add Etch to your home screen and play offline. Hosted at /projects/etch/.' },
];

/**
 * Lazy-loaded "what's new in v0.4.0" popover. Surfaces the headline changes
 * from CHANGELOG.md in a compact list. Self-closing once dismissed (persists).
 */
export function WhatsNewSheet({ onClose }: Props) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const node = ref.current;
    if (!node) return;
    const release = trapFocus(node);
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') onClose(); }
    window.addEventListener('keydown', onKey);
    return () => { release(); window.removeEventListener('keydown', onKey); };
  }, [onClose]);

  return (
    <div className="etch-wn-backdrop" role="dialog" aria-modal="true" aria-label="What's new" onClick={onClose}>
      <div className="etch-wn-sheet" ref={ref} onClick={(e) => e.stopPropagation()}>
        <header>
          <span className="etch-wn-eyebrow">v0.4.0</span>
          <h2>What's new</h2>
          <button className="etch-wn-close" aria-label="Close" onClick={onClose}>×</button>
        </header>
        <ul className="etch-wn-list">
          {ITEMS.map((it) => (
            <li key={it.tag}>
              <strong>{it.tag}.</strong> {it.body}
            </li>
          ))}
        </ul>
        <footer>
          <button type="button" className="etch-wn-ok" onClick={onClose}>Got it</button>
        </footer>
      </div>
    </div>
  );
}

export default WhatsNewSheet;
